(()=>{var e=()=>{const e=document.getElementById("header-nav"),t=document.getElementById("content");if(!e||!t){console.warn("[Scroll Header] 未找到 #header-nav 或 #content 元素！");return}const s=Math.min(window.innerHeight*.5,t.getBoundingClientRect().top+window.scrollY),n=()=>{const t=window.scrollY>=s;e.classList.toggle("header-nav-visible",t)};window.addEventListener("scroll",n),n()};document.addEventListener("DOMContentLoaded",e)})()